/*
 * Load Balancer Simulation - C Implementation
 * ==============================================
 * Demonstrates weighted round-robin load balancing,
 * a key technology for scalable internet computing.
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_SERVERS 5
#define MAX_REQUESTS 100

// Server structure representing a backend server
typedef struct {
    char name[20];
    int capacity;        // Relative capacity/weight
    int current_load;    // Current number of active requests
    int total_requests;  // Total requests handled
    int is_healthy;      // Health status (1 = healthy, 0 = down)
} Server;

// Request structure
typedef struct {
    int request_id;
    int priority;
} Request;

// Global server array
Server servers[MAX_SERVERS];
int server_count = 0;

// Function to initialize servers
void init_servers() {
    // Create sample servers with different capacities
    strcpy(servers[0].name, "Server1");
    servers[0].capacity = 100;
    servers[0].current_load = 0;
    servers[0].total_requests = 0;
    servers[0].is_healthy = 1;

    strcpy(servers[1].name, "Server2");
    servers[1].capacity = 200;  // Higher capacity
    servers[1].current_load = 0;
    servers[1].total_requests = 0;
    servers[1].is_healthy = 1;

    strcpy(servers[2].name, "Server3");
    servers[2].capacity = 150;
    servers[2].current_load = 0;
    servers[2].total_requests = 0;
    servers[2].is_healthy = 1;

    server_count = 3;
}

// Weighted Round-Robin selection
// Servers with higher capacity get more requests
int select_server_weighted_rr() {
    static int current_index = 0;
    static int current_weight = 0;

    int attempts = 0;
    int selected = -1;

    // Try to find the best server
    while (attempts < server_count) {
        Server *srv = &servers[current_index];

        if (srv->is_healthy) {
            if (current_weight <= 0) {
                current_weight = srv->capacity;
            }

            if (current_weight > 0) {
                selected = current_index;
                current_weight--;
                break;
            }
        }

        current_index = (current_index + 1) % server_count;
        attempts++;
    }

    // Fallback: find any healthy server
    if (selected == -1) {
        for (int i = 0; i < server_count; i++) {
            if (servers[i].is_healthy) {
                selected = i;
                break;
            }
        }
    }

    return selected;
}

// Process a single request
void process_request(int request_id) {
    int server_idx = select_server_weighted_rr();

    if (server_idx == -1) {
        printf("Request %d: No healthy server available!\n", request_id);
        return;
    }

    // Simulate request processing
    servers[server_idx].current_load++;
    servers[server_idx].total_requests++;

    printf("Request %d -> %s (Load: %d)\n", 
           request_id, 
           servers[server_idx].name, 
           servers[server_idx].current_load);

    // Simulate request completion
    servers[server_idx].current_load--;
}

// Simulate server failure
void simulate_failure(int server_idx) {
    if (server_idx >= 0 && server_idx < server_count) {
        servers[server_idx].is_healthy = 0;
        printf("\n*** ALERT: %s is now DOWN! ***\n", servers[server_idx].name);
    }
}

// Display server statistics
void display_statistics() {
    printf("\n========================================\n");
    printf("       SERVER STATISTICS\n");
    printf("========================================\n");
    printf("%-10s | %-8s | %-6s | %s\n", 
           "Server", "Capacity", "Status", "Total Req");
    printf("----------------------------------------\n");

    for (int i = 0; i < server_count; i++) {
        printf("%-10s | %-8d | %-6s | %d\n",
               servers[i].name,
               servers[i].capacity,
               servers[i].is_healthy ? "UP" : "DOWN",
               servers[i].total_requests);
    }
    printf("========================================\n");
}

int main() {
    printf("LOAD BALANCER SIMULATION\n");
    printf("========================\n\n");

    // Initialize servers
    init_servers();

    // Simulate incoming requests
    printf("Processing incoming requests...\n\n");

    for (int i = 1; i <= 15; i++) {
        process_request(i);
    }

    // Display statistics after initial distribution
    display_statistics();

    // Simulate a server failure
    printf("\n--- Simulating Server2 failure ---\n");
    simulate_failure(1);

    // Continue processing with reduced capacity
    printf("\nProcessing more requests...\n");
    for (int i = 16; i <= 20; i++) {
        process_request(i);
    }

    // Final statistics
    display_statistics();

    printf("\nKEY CONCEPTS DEMONSTRATED:\n");
    printf("- Weighted Round-Robin distribution\n");
    printf("- Automatic failover on server failure\n");
    printf("- Load-based request routing\n");
    printf("- Fault tolerance in distributed systems\n");

    return 0;
}
